void euclid_openmp(LatLong *locations, float *distances, int numRecords, float lat, float lng)
{
    #pragma omp parallel for
    for (int globalId = 0; globalId < numRecords; ++globalId) {
        LatLong *latLong = &locations[globalId];
        float d = (float)sqrt((lat-latLong->lat)*(lat-latLong->lat)+(lng-latLong->lng)*(lng-latLong->lng));
        distances[globalId] = d;
    }
}

